#include <stdio.h>
#include <string.h>
#include <ctype.h>

int digitsNum(int x, int base) {
    int ret = 0;
    while (x > 0) {
        ret += 1;
        x /= base;
    }
    return ret;
}

int maxDigit(const char *s) {
    int max = 0;
    for (int i = 0; s[i]; i++) {
        int d = isdigit(s[i]) ? s[i] - '0' : toupper(s[i]) - 'A' + 10;
        if (d > max) max = d;
    }
    return max;
}

int strToInt(const char *s, int base) {
    int res = 0;
    for (int i = 0; s[i]; i++) {
        res = res * base + (isdigit(s[i]) ? s[i] - '0' : toupper(s[i]) - 'A' + 10);
    }
    return res;
}

int main() {
    char n[100], m[100];
    scanf("%s %s", n, m);

    int base_n = maxDigit(n);
    int base_m = maxDigit(m);
    int base = (base_n > base_m ? base_n : base_m) + 1;

    int num_n = strToInt(n, base);
    int num_m = strToInt(m, base);

    printf("%d\n", digitsNum(num_n + num_m, base));
    return 0;
}
